sql:
SELECT AVG(movies.revenue) AS average_revenue
FROM movies
JOIN rotten_tomatoes ON movies.movie_id = rotten_tomatoes.movie_id;

external_knowledge:
- "Beacons of critical acclaim" refers to movies that have received high scores from critics;
- "Lighting up the cinematic sky since 2010" implies the movies were released after 2010;
- "Unified praise across Rotten Tomatoes, Metacritic, and IMDb shining brighter than 7.0" indicates the average critic score from the three platforms is 7.0 or higher.

sql:
SELECT SUM(revenue) AS total_overall_revenue
FROM movies
WHERE budget > (SELECT AVG(budget) FROM movies);
